import type { FormActionPermissions } from '../services/voucherInit/endpoint';
import type { DocumentPostingStatus } from '../services/kt/models';
import { canViewVoucherLedgerFromForm } from './voucherListRowActions';
import {
  canShowVoucherEditDelete,
  canVoucherApprove,
  type AccountingPeriodGate,
} from './voucherToolbarActions';

export interface ResolveVoucherFormToolbarFlagsInput {
  formPermissions: FormActionPermissions | null | undefined;
  isNew: boolean;
  status: string;
  processingLevel: string;
  voucherDate: string;
  id?: string | null;
  postingStatus?: DocumentPostingStatus | string;
  accountingPeriods?: AccountingPeriodGate[];
  /** Default true — CTNB dùng phê duyệt batch trên list → false */
  enableApproveToolbar?: boolean;
}

export interface VoucherFormToolbarFlags {
  showEditDelete: boolean;
  showEditButton: boolean;
  showDeleteButton: boolean;
  canDeleteToolbar: boolean;
  canSaveToolbar: boolean;
  canEditToolbar: boolean;
  showNewButton: boolean;
  showApproveToolbar: boolean;
  canApproveToolbar: boolean;
  canPrintToolbar: boolean;
  canCopyToolbar: boolean;
  canViewLedgerToolbar: boolean;
}

/**
 * Map init-data `formPermissions` + nghiệp vụ → cờ toolbar form chứng từ.
 * SSOT parity: `useCashVoucherFormController` (Phiếu thu/chi).
 */
export function resolveVoucherFormToolbarFlags(
  input: ResolveVoucherFormToolbarFlagsInput,
): VoucherFormToolbarFlags {
  const fp = input.formPermissions;
  const showEditDelete =
    canShowVoucherEditDelete(input.status, input.processingLevel, input.isNew)
    && (fp?.canUpdate ?? false);

  const canApprovePermission = fp?.canUnpost ?? fp?.canApprove ?? false;
  const enableApprove = input.enableApproveToolbar ?? true;
  const showApproveToolbar = enableApprove && !input.isNew && canApprovePermission;
  const canApproveToolbar =
    showApproveToolbar
    && canVoucherApprove({
      isNew: input.isNew,
      status: input.status,
      processingLevel: input.processingLevel,
      voucherDate: input.voucherDate,
      periods: input.accountingPeriods ?? [],
    });

  const canViewLedgerToolbar = canViewVoucherLedgerFromForm({
    isNew: input.isNew,
    id: input.id,
    status: input.status,
    processingLevel: input.processingLevel,
    postingStatus: input.postingStatus ?? 'None',
    canViewLedgerPermission: fp?.canViewLedger ?? false,
  });

  const canDeleteToolbar = showEditDelete && (fp?.canDelete ?? false);

  return {
    showEditDelete,
    showEditButton: showEditDelete,
    showDeleteButton: canDeleteToolbar,
    canDeleteToolbar,
    canSaveToolbar: input.isNew ? (fp?.canCreate ?? false) : showEditDelete,
    canEditToolbar: showEditDelete,
    showNewButton: fp?.canCreate ?? false,
    showApproveToolbar,
    canApproveToolbar,
    canPrintToolbar: !input.isNew && (fp?.canPrint ?? false),
    canCopyToolbar: !input.isNew && (fp?.canCopy ?? false),
    canViewLedgerToolbar,
  };
}
